mapper.update:
UPDATE pt_member_private_benefit
SET frozen_lessons = frozen_lessons + #{n},
    remaining_lessons = remaining_lessons - #{n}
WHERE id = #{id} AND status = 1 AND remaining_lessons >= #{n}

UPDATE pt_member_private_benefit
SET frozen_lessons = frozen_lessons - #{n},
    used_lessons = used_lessons + #{n}
WHERE id = #{id} AND frozen_lessons >= #{n}

UPDATE pt_member_private_benefit
SET frozen_lessons = frozen_lessons - #{n},
    remaining_lessons = remaining_lessons + #{n}
WHERE id = #{id} AND frozen_lessons >= #{n}

UPDATE pt_member_private_benefit
SET total_lessons = total_lessons - #{n},
    remaining_lessons = remaining_lessons - #{n}
WHERE id = #{id} AND remaining_lessons >= #{n}

mapper.select:
SELECT COUNT(*)
FROM pt_member_private_benefit
WHERE product_id = #{productId}
